// ─── Extended seed data ───────────────────────────────────────────────────────
// Math.random() inside means this would produce different arrays on server vs
// client if evaluated at module load → React hydration mismatch on any rendered
// stat or list. Wrapped as a function and called from a useEffect in App so
// the seed only generates client-side after mount.
const generateExtraPeople = () => {
  const stages = ['New','Attempting','Nurturing','Request','Job in Progress','Final Processing','Closed Won','Closed Lost']
  const sources = getLeadSources()
  const projects = ['Home Organization','Kitchen + Pantry','Closet + Office','Garage','Full Home','Move-In Organization','Bedroom + Closet','Basement','Attic','Master Closet','Pantry','Mudroom + Entry']
  const paths = ['email-nurture','quick-connect','personal-touch','general-a','general-b']
  const tags = [['hot'],['referral'],['returning'],['vip'],['warm'],[],['hot','referral'],[]]

  // Real users mapped to real location IDs
  const users = [
    {id:'u1', lid:'loc_kc',        init:'LE'},
    {id:'u2', lid:'loc_nwarkansas',init:'TY'},
    {id:'u3', lid:'loc_okc',       init:'CW'},
    {id:'u4', lid:'loc_omaha',     init:'MC'},
    {id:'u5', lid:'loc_palmbeach', init:'AP'},
    {id:'u6', lid:'loc_portland',  init:'WE'},
    {id:'u7', lid:'loc_sanantonio',init:'RG'},
    {id:'u8', lid:'loc_scottsdale',init:'AA'},
    {id:'u9', lid:'loc_seattle',   init:'SA'},
    {id:'u10',lid:'loc_temecula',  init:'MS'},
  ]

  const locationData = [
    {id:'loc_kc',         city:'Kansas City',      state:'KS', zip:'64111', userIds:['u1','u11']},
    {id:'loc_nwarkansas', city:'Northwest Arkansas',state:'AR', zip:'72701', userIds:['u2']},
    {id:'loc_okc',        city:'Oklahoma City',    state:'OK', zip:'73102', userIds:['u3']},
    {id:'loc_omaha',      city:'Omaha',            state:'NE', zip:'68102', userIds:['u4']},
    {id:'loc_palmbeach',  city:'Palm Beach',       state:'FL', zip:'33480', userIds:['u5']},
    {id:'loc_portland',   city:'Portland',         state:'OR', zip:'97201', userIds:['u6']},
    {id:'loc_sanantonio', city:'San Antonio',      state:'TX', zip:'78201', userIds:['u7']},
    {id:'loc_scottsdale', city:'Scottsdale',       state:'AZ', zip:'85251', userIds:['u8']},
    {id:'loc_seattle',    city:'Seattle',          state:'WA', zip:'98101', userIds:['u9']},
    {id:'loc_temecula',   city:'Temecula',         state:'CA', zip:'92590', userIds:['u10']},
  ]
  const streets = ['Maple St','Oak Ave','Pine Rd','Elm Dr','Cedar Ln','Birch Way','Walnut Blvd','Spruce Ct','Aspen Pl','Willow Ln','Cherry St','Peach Ave']
  const firstNames = ['Ashley','Brittany','Catherine','Danielle','Emily','Frances','Grace','Hannah','Isabella','Jessica','Katherine','Lauren','Melissa','Nicole','Olivia','Patricia','Rachel','Stephanie','Taylor','Victoria','Amanda','Brenda','Christine','Deborah','Elizabeth','Gina','Holly','Irene','Jennifer','Kimberly','Linda','Michelle','Nancy','Pamela','Rebecca','Sandra','Theresa','Valerie','Wendy','Yvonne','James','Robert','Michael','William','David','Richard','Charles','Joseph','Thomas','Christopher','Matthew','Anthony','Daniel','Steven','Paul','Andrew','Brian','Mark','Edward','Ronald','George','Timothy','Jason','Jeffrey','Ryan','Gary','Nicholas','Eric','Jacob','Jonathan']
  const lastNames = ['Anderson','Baker','Campbell','Davis','Evans','Foster','Garcia','Harris','Jackson','Johnson','King','Lewis','Martin','Nelson','Parker','Quinn','Roberts','Smith','Taylor','Thompson','Walker','White','Williams','Wilson','Young','Allen','Bell','Brooks','Carter','Clark','Coleman','Cooper','Cox','Cruz','Diaz','Edwards','Flores','Gonzalez','Green','Hall','Hill','Howard','Hughes','James','Jones','Kelly','Lee','Lopez','Mitchell','Moore','Morgan','Murphy','Myers','Perez','Phillips','Price','Reed','Rivera','Robinson','Rodriguez','Rogers','Ross','Sanders','Scott','Torres','Turner']
  
  const pick = arr => arr[Math.floor(Math.random()*arr.length)]
  const rnd = (min,max) => Math.floor(Math.random()*(max-min+1))+min
  
  const results = []
  let id = 100
  
  locationData.forEach(loc => {
    const count = loc.id==='loc_kc' ? 20 : loc.id==='loc_scottsdale' ? 18 : loc.id==='loc_seattle' ? 16 : 10
    for (let i=0; i<count; i++) {
      const firstName = pick(firstNames)
      const lastName = pick(lastNames)
      const stage = pick(stages)
      const user = pick(users.filter(u=>u.lid===loc.id))
      const month = pick(['Jan','Feb','Mar','Apr','May'])
      const day = rnd(1,28)
      const isPaid = Math.random()>0.4
      const hasInvoice = ['Job in Progress','Final Processing','Closed Won'].includes(stage)
      const hasJobber = ['Request','Request','Job in Progress','Final Processing','Closed Won'].includes(stage)
      
      results.push({
        id: String(id++),
        assignedTo: user?.id||'u1',
        locationId: loc.id,
        name: `${firstName} ${lastName}`,
        phone: `(${rnd(300,999)}) ${rnd(200,999)}-${String(rnd(1000,9999))}`,
        email: `${firstName.toLowerCase()}.${lastName.toLowerCase()}@${pick(['gmail.com','yahoo.com','outlook.com','email.com','me.com','icloud.com'])}`,
        stage,
        source: pick(sources),
        project: pick(projects),
        created: `${month} ${day}`,
        address: `${rnd(100,9999)} ${pick(streets)}, ${loc.city} ${loc.state} ${loc.zip}`,
        addresses:[{type:'Service',value:`${rnd(100,9999)} ${pick(streets)}, ${loc.city} ${loc.state} ${loc.zip}`}],
        reachOutMethod: stage==='New'?null:pick(['call','email','sms']),
        jobberSearchStatus: 'not_found',
        jobberClient: null,
        path: pick(paths),
        assessment: ['Request'].includes(stage)?`May ${rnd(6,30)} at ${rnd(9,16)}:00 ${rnd(0,1)?'AM':'PM'}`:null,
        assessmentType: Math.random()>0.3?'in-person':'virtual',
        jobberRef: hasJobber?`${pick(['REQ','JOB'])}-${rnd(1000,9999)}`:null,
        tags: pick(tags),
        isJunk: stage==='Closed Lost'&&Math.random()>0.3,
        junkReason: stage==='Closed Lost'?pick(['Out of Budget','Not Responsive','Went with Competitor','Wrong Fit',null]):null,
        buzzNotes: Math.random()>0.6?[{id:`bn${id}`,text:pick(['Prefers morning appointments','Has a dog - heads up','Gate code: 1234','Very detail-oriented','Referred by a friend','Returns calls quickly','Prefers text','Large project - needs team']),ts:`${month} ${day}`,user:'You'}]:[],
        jobNotes: [],
        jobs: hasJobber&&stage!=='Request'?[{id:`job${id}`,jobberRef:`JOB-${rnd(1000,9999)}`,title:pick(projects)+' Organization',status:stage==='Closed Won'?'Completed':'In Progress',scheduledDate:`Apr ${rnd(1,30)}, 2026`,team:[pick(['Jessica R.','Maria L.','Ana G.','Tom C.'])]}]:[],
        invoices: hasInvoice?[{id:`inv${id}`,number:`INV-${rnd(1000,9999)}`,amount:rnd(350,2200),status:isPaid?'Paid':'Awaiting Payment',date:`Apr ${rnd(1,30)}`}]:[],
        finalProcessed: stage==='Closed Won'&&Math.random()>0.5,
        outreachTimeline: [{id:`o${id}`,type:'drip',method:'email',label:'Welcome Email sent',ts:`${month} ${day}, 9:00am`,status:'sent'}],
        activity: [{type:'system',text:`Client created from ${pick(sources)}`,ts:`${month} ${day}`}],
      })
    }
  })
  return results
}


