function ReachOutPopup({ person, onDone, onClose }) {
  const [method, setMethod] = useState(null)
  const [note, setNote] = useState('')
  const methods = [{key:'call',icon:'📞',label:'Phone Call'},{key:'sms',icon:'💬',label:'Text'},{key:'email',icon:'📧',label:'Email'}]

  function confirm() {
    if (!method) return
    const labels = {call:'Phone Call',sms:'Text',email:'Email'}
    const newEntry = { id:`o${Date.now()}`, type:'manual', method, label:`Reached out via ${labels[method]}${note?' - '+note:''}`, ts:'Just now', status:'done', user:'You' }
    const isFirst = !person.reachOutMethod
    onDone({
      reachOutMethod: person.reachOutMethod||method,
      stage: isFirst?'Attempting':person.stage,
      outreachTimeline: [...person.outreachTimeline, newEntry],
    })
  }

  return (
    <Popup title="Log Reach Out" onClose={onClose}>
      <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>You can log multiple reach-outs. Each will appear in the outreach timeline.</p>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'8px', marginBottom:'1rem' }}>
        {methods.map(m=>(
          <button key={m.key} onClick={()=>setMethod(m.key)} style={{ padding:'14px 8px', borderRadius:'12px', cursor:'pointer', border:'2px solid', borderColor:method===m.key?'#a8c9c4':'rgba(0,0,0,0.08)', background:method===m.key?'rgba(168,201,196,0.12)':'white', display:'flex', flexDirection:'column', alignItems:'center', gap:'6px', fontFamily:'inherit' }}>
            <span style={{ fontSize:'24px' }}>{m.icon}</span>
            <span style={{ fontSize:'12px', fontWeight:600, color:'#1a2e2b' }}>{m.label}</span>
          </button>
        ))}
      </div>
      <input style={{...inp, marginBottom:'1.25rem'}} placeholder="Notes - left voicemail, no answer, etc." value={note} onChange={e=>setNote(e.target.value)} />
      <div style={{ display:'flex', gap:'10px' }}>
        <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
        <button onClick={confirm} disabled={!method} style={{ flex:2, padding:'12px', background:method?'#f97316':'#e5e7eb', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:method?'white':'#9ca3af', cursor:method?'pointer':'not-allowed' }}>Log Reach Out</button>
      </div>
    </Popup>
  )
}

// ─── Tag Manager Popup ────────────────────────────────────────────────────────
function TagPopup({ person, onSave, onClose }) {
  const [selected, setSelected] = useState([...person.tags])

  function toggle(id) {
    setSelected(prev => prev.includes(id) ? prev.filter(x=>x!==id) : [...prev, id])
  }

  return (
    <Popup title="Tags" onClose={onClose}>
      <p style={{ fontSize:'13px', color:'#8a9e9a', marginBottom:'1rem' }}>Tag this client to help with filtering and follow-up.</p>
      <div style={{ display:'grid', gap:'8px', marginBottom:'1.25rem' }}>
        {ALL_TAGS.map(tag=>{
          const active = selected.includes(tag.id)
          return (
            <button key={tag.id} onClick={()=>toggle(tag.id)} style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'11px 14px', background:active?tag.bg:'white', border:`1.5px solid ${active?tag.color+'50':'rgba(0,0,0,0.08)'}`, borderRadius:'10px', cursor:'pointer', fontFamily:'inherit' }}>
              <span style={{ fontSize:'14px', fontWeight:500, color:active?tag.color:'#1a2e2b' }}>{tag.label}</span>
              <div style={{ width:'20px', height:'20px', borderRadius:'6px', border:`2px solid ${active?tag.color:'rgba(0,0,0,0.15)'}`, background:active?tag.color:'white', display:'flex', alignItems:'center', justifyContent:'center' }}>
                {active&&<span style={{ fontSize:'11px', color:'white', fontWeight:700 }}>✓</span>}
              </div>
            </button>
          )
        })}
      </div>
      <div style={{ display:'flex', gap:'10px' }}>
        <button onClick={onClose} style={{ flex:1, padding:'12px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
        <button onClick={()=>onSave(selected)} style={{ flex:2, padding:'12px', background:'#1a2e2b', border:'none', borderRadius:'10px', fontSize:'14px', fontFamily:'inherit', fontWeight:500, color:'white', cursor:'pointer' }}>Save Tags</button>
      </div>
    </Popup>
  )
}

