// ─── Address Modal (centered popup for partners/contacts/companies/settings) ──
function AddressModal({ addr=null, onSave, onDelete=null, onClose }) {
  const [type, setType] = useState(addr?.type||'Business')
  const [street, setStreet] = useState(addr?.value||'')
  const [city, setCity]   = useState('')
  const [state, setState] = useState('')
  const [zip, setZip]     = useState('')
  const lbl = { fontSize:'11px', fontWeight:600, color:'#4a5e5a', textTransform:'uppercase', letterSpacing:'0.5px', marginBottom:'5px', display:'block' }
  const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'8px', fontSize:'16px', fontFamily:'inherit', color:'#1a2e2b', outline:'none', boxSizing:'border-box', background:'white' }
  const canSave = street.trim().length > 5
  const fullValue = [street.trim(), [city,state,zip].filter(Boolean).join(' ')].filter(Boolean).join(', ')

  return (
    <Popup title={addr?'Edit Address':'Add Address'} onClose={onClose}>
      <div style={{ display:'grid', gap:'12px' }}>
        <div>
          <label style={lbl}>Address Type</label>
          <select value={type} onChange={e=>setType(e.target.value)} style={{...inp, appearance:'none'}}>
            {ADDRESS_TYPES.map(t=><option key={t}>{t}</option>)}
          </select>
        </div>
        <div>
          <label style={lbl}>Street Address</label>
          <AddressAutofill
            value={street}
            onChange={setStreet}
            onParsed={p=>{ setStreet(p.street); setCity(p.city); setState(p.state); setZip(p.zip) }}
            placeholder="Start typing a street address…"
          />
        </div>
        {(street.length>5||city||state)&&(
          <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr 1fr', gap:'8px' }}>
            <div><label style={{...lbl,marginBottom:'4px'}}>City</label><input value={city} onChange={e=>setCity(e.target.value)} placeholder="City" style={inp} /></div>
            <div><label style={{...lbl,marginBottom:'4px'}}>State</label><input value={state} onChange={e=>setState(e.target.value)} placeholder="ST" maxLength={2} style={inp} /></div>
            <div><label style={{...lbl,marginBottom:'4px'}}>ZIP</label><input value={zip} onChange={e=>setZip(e.target.value)} placeholder="ZIP" style={inp} /></div>
          </div>
        )}
        <div style={{ display:'flex', gap:'8px', marginTop:'4px' }}>
          {onDelete&&<button onClick={onDelete} style={{ padding:'11px 14px', background:'none', border:'1px solid rgba(239,68,68,0.2)', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', color:'#ef4444', cursor:'pointer' }}>Delete</button>}
          <button onClick={onClose} style={{ flex:1, padding:'11px', background:'transparent', border:'1.5px solid rgba(0,0,0,0.1)', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', color:'#4a5e5a', cursor:'pointer' }}>Cancel</button>
          <button onClick={()=>canSave&&onSave({type,value:fullValue})} disabled={!canSave}
            style={{ flex:2, padding:'11px', background:canSave?'#1a2e2b':'#e5e7eb', border:'none', borderRadius:'9px', fontSize:'13px', fontFamily:'inherit', fontWeight:600, color:canSave?'white':'#9ca3af', cursor:canSave?'pointer':'not-allowed' }}>
            Save Address
          </button>
        </div>
      </div>
    </Popup>
  )
}

